class Solution(object):
    def addMinimum(self, word):
        abc = "abc"
        j = 0  # pointer into "abc"
        additions = 0
        for c in word:
            # Advance j until it matches c, counting skipped positions
            while abc[j] != c:
                additions += 1
                j = (j + 1) % 3
            j = (j + 1) % 3  # move past matched character
        # After processing, if j != 0, we need to finish the last "abc" group
        if j != 0:
            additions += (3 - j)
        return additions
